import React, { memo, useCallback } from 'react';
import { CELL } from '../constants';

const BoardCell = memo(({ row, col, cell, isYourBoard, isYourTurn, onCellClick, showExplosion, isFocused, isLastShot }) => {
    const clickable =
        !isYourBoard &&
        isYourTurn &&
        cell !== CELL.HIT &&
        cell !== CELL.MISS &&
        cell !== CELL.SUNK &&
        cell !== CELL.SAFE;

    const handleClick = useCallback(() => {
        if (clickable) onCellClick(row, col);
    }, [row, col, clickable, onCellClick]);

    let bg, label;
    switch (cell) {
        case CELL.SHIP: bg = isYourBoard ? 'bg-emerald-500' : 'bg-blue-400/80'; label = isYourBoard ? '⚓' : null; break;
        case CELL.HIT: bg = 'bg-orange-500'; label = '🔥'; break;
        case CELL.MISS: bg = 'bg-slate-500/70'; label = null; break;
        case CELL.SUNK: bg = 'bg-red-800'; label = '💀'; break;
        case CELL.SAFE: bg = 'bg-slate-700/50'; label = null; break;
        default: bg = 'bg-blue-500/70'; label = null;
    }

    return (
        <button
            type="button"
            onClick={handleClick}
            disabled={!clickable}
            className={`
        aspect-square w-full flex items-center justify-center relative overflow-hidden
        border border-slate-800/40 transition-all duration-75 select-none
        text-[clamp(1rem,4vw,2rem)]
        ${bg}
        ${clickable ? 'cursor-crosshair hover:brightness-125 hover:scale-110 hover:z-10' : 'cursor-default'}
        ${cell === CELL.MISS ? 'after:content-["·"] after:text-slate-300 after:font-black after:text-2xl' : ''}
        ${isFocused ? 'cell-focus-ring' : ''}
        ${isLastShot ? 'animate-shot-pop' : ''}
      `}
            aria-label={`${String.fromCharCode(65 + col)}${row + 1}`}
        >
            {showExplosion && (
                <img
                    src="/assets/ship-sink-explosion.webp"
                    alt=""
                    className="absolute inset-0 w-full h-full object-cover z-10 pointer-events-none"
                />
            )}
            {label}
        </button>
    );
}, (prev, next) =>
    prev.cell === next.cell &&
    prev.isYourBoard === next.isYourBoard &&
    prev.isYourTurn === next.isYourTurn &&
    prev.onCellClick === next.onCellClick &&
    prev.showExplosion === next.showExplosion &&
    prev.isFocused === next.isFocused &&
    prev.isLastShot === next.isLastShot
);

BoardCell.displayName = 'BoardCell';

export default BoardCell;
